public static ETG_PurchaseShippingInstructionsDP construct()
{
    ETG_PurchaseShippingInstructionsDP  dataProvider;

    dataProvider = new ETG_PurchaseShippingInstructionsDP();

    return dataProvider;
}

public ETG_PurchaseShippingInstructionsTmp processReport (ETG_PurchaseShippingInstructionsContract _contract)
{
    PurchAgreementId            purchAgreementId;
    PurchAgreementHeader        purchAgreementHeader;

    purchAgreementId        =   _contract.parmPurchaseAgreementId();
    purchAgreementHeader    =   PurchAgreementHeader::findAgreementId(purchAgreementId);

    purchShippingTmp.PurchNumberSequence    =   purchAgreementHeader.PurchNumberSequence;
    purchShippingTmp.VendAccount            =   purchAgreementHeader.VendAccount;

    ttsbegin;
    purchShippingTmp.insert();
    ttscommit;

    // Select all rows from tmp table and return
    select purchShippingTmp;
    return purchShippingTmp;
}
